import React, { useState, useEffect } from "react";
import FriendList from "./FriendList";
import NotificationList from "./NotificationList";
import ChatSocket from "./ChatSocket";

export default function HomePage() {
  const [screen, setScreen] = useState("newfeed"); // newfeed | friends | notifications
  const [input1, onChangeInput1] = useState('');
  const [input2, onChangeInput2] = useState('');
  const [toast, setToast] = useState(null);
  const [user, setUser] = useState(null); // Thông tin user đã đăng nhập
  const [token, setToken] = useState(null); // JWT token

  const [comments, setComments] = useState([
    { input: '', list: [], likes: 0 },
    { input: '', list: [], likes: 0 },
    { input: '', list: [], likes: 0 },
  ]);

  const showToast = (message) => {
    setToast(message);
    setTimeout(() => setToast(null), 2500);
  };

  // Kiểm tra localStorage để lấy thông tin đăng nhập
  useEffect(() => {
    const savedUser = localStorage.getItem('user');
    const savedToken = localStorage.getItem('token');
    if (savedUser && savedToken) {
      setUser(JSON.parse(savedUser));
      setToken(savedToken);
    }
  }, []);

  // Nếu không phải newfeed thì hiển thị FriendList hoặc NotificationList
  if (screen === "friends") return <FriendList goBack={() => setScreen("newfeed")} />;
  if (screen === "notifications") return <NotificationList goBack={() => setScreen("newfeed")} />;

  return (
    <div className="flex min-h-screen bg-gray-100">
      {/* Nội dung chính */}
      <div className="flex-1 flex flex-col">
        {/* Header cố định */}
        <div className="fixed top-0 left-0 right-0 flex items-center justify-between bg-[#88BCF8] py-3 px-6 z-50">
          <div className="flex items-center flex-shrink-0">
            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/iitooitd_expires_30_days.png"
              className="w-[120px] h-[110px] object-fill"
              alt="logo"
            />
          </div>

          <div className="flex items-center gap-2 max-w-[600px] w-full mx-6">
            <input
              placeholder="Nhập để tìm kiếm"
              value={input1}
              onChange={(e) => onChangeInput1(e.target.value)}
              className="text-black bg-[#F6FEFF] text-base flex-1 py-2 px-5 rounded-[50px] border-0 outline-none"
            />
            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/qfk5vizv_expires_30_days.png"
              alt="search-icon"
              className="w-[45px] h-[45px] cursor-pointer hover:scale-110 transition-transform duration-200"
            />
          </div>

          <div className="flex items-center gap-5 flex-shrink-0">
            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/nuk8gi0s_expires_30_days.png"
              className="w-[45px] h-[45px] object-contain cursor-pointer hover:scale-110 transition-transform duration-200"
              alt="settings-icon"
            />
            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/ceqzh6wh_expires_30_days.png"
              className="w-[45px] h-[45px] object-contain cursor-pointer hover:scale-110 transition-transform duration-200"
              alt="game-icon"
            />
          </div>
        </div>

        {/* Feed scrollable */}
        <div className="mt-[120px] px-6 flex flex-col items-center gap-6">
          {/* Toast */}
          {toast && (
            <div className="fixed top-[120px] right-10 bg-black text-white px-6 py-3 rounded-lg shadow-lg z-50 animate-slide-down">
              {toast}
            </div>
          )}

          {/* Nút Chào bạn */}
          <button
            className="w-full max-w-[1000px] bg-[#FFDEF8CF] py-3 rounded-[8px] -mt-2"
            onClick={() => showToast("Xin chào bạn!")}
          >
            <span className="text-black text-xl">Chào bạn</span>
          </button>

          {/* Input đăng bài */}
          <div className="flex items-center bg-[#A2D3FF] py-3 px-6 rounded-[10px] w-full max-w-[1000px]">
            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/d7m3bryx_expires_30_days.png"
              className="w-[58px] h-[58px] mr-4"
              alt="avatar"
            />
            <input
              placeholder="Hôm nay bạn thế nào chia sẻ với tui đi!!"
              value={input2}
              onChange={(e) => onChangeInput2(e.target.value)}
              className="text-black bg-[#F6FEFF] text-xl flex-1 py-2 px-4 rounded-[50px] border-0"
            />
            <button
              className="ml-4 bg-blue-400 text-white px-4 py-2 rounded-lg"
              onClick={() => {
                if (input2.trim() !== "") {
                  showToast(`Bạn vừa gửi: "${input2}"`);
                  onChangeInput2('');
                  setTimeout(() => showToast("Bạn của bạn đăng tin"), 500);
                }
              }}
            >
              Gửi
            </button>
          </div>

          {/* Bài post */}
          {[0, 1, 2].map((i) => (
            <div key={i} className="flex flex-col bg-[#A2D3FF] w-full max-w-[1000px] p-4 rounded-[10px] gap-4">
              {/* Header bài post */}
              <div className="flex items-center gap-4">
                <img
                  src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/oadiyd0v_expires_30_days.png"
                  className="w-[58px] h-[51px]"
                  alt="avatar"
                />
                <div className="flex flex-col">
                  <span className="text-black text-xl">Nickname</span>
                  <span className="text-black text-base">công khai</span>
                </div>
              </div>

              {/* Hình ảnh */}
              <div className="flex gap-4">
                <img
                  src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/nwti4bgy_expires_30_days.png"
                  className="w-1/2 rounded-lg"
                  alt="post1"
                />
                <img
                  src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/3cxpt7rg_expires_30_days.png"
                  className="w-1/2 rounded-lg"
                  alt="post2"
                />
              </div>

              {/* Bình luận */}
              <div className="flex items-center gap-2 mt-2">
                <img
                  src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/gyfive3m_expires_30_days.png"
                  className="w-[39px] h-[45px] rounded-[10px] transition-transform duration-300 cursor-pointer"
                  alt="like"
                  onClick={(e) => {
                    const target = e.currentTarget;
                    target.classList.add('scale-up');
                    setTimeout(() => target.classList.remove('scale-up'), 300);
                  }}
                />
                <input
                  placeholder="Bình luận"
                  value={comments[i]?.input || ''}
                  onChange={(e) => {
                    const newComments = [...comments];
                    newComments[i].input = e.target.value;
                    setComments(newComments);
                  }}
                  className="flex-1 py-2 px-4 rounded-lg text-black border-0"
                />
                <button
                  className="bg-blue-500 text-white px-3 py-1 rounded-lg"
                  onClick={() => {
                    if (!comments[i]?.input?.trim()) return;
                    const newComments = [...comments];
                    if (!newComments[i].list) newComments[i].list = [];
                    newComments[i].list.push(newComments[i].input);
                    newComments[i].input = '';
                    setComments(newComments);
                  }}
                >
                  Gửi
                </button>
              </div>

              {/* Danh sách bình luận */}
              {comments[i]?.list?.length > 0 && (
                <div className="mt-2 ml-12 flex flex-col gap-1">
                  {comments[i].list.map((cmt, idx) => (
                    <span key={idx} className="text-black text-sm bg-white px-2 py-1 rounded-lg">
                      {cmt}
                    </span>
                  ))}
                </div>
              )}
            </div>
          ))}

        </div>

        {/* --- Chat Box cố định ở góc dưới phải --- */}
        <ChatSocket user={{ id: 'guest', display_name: 'Guest' }} />

      </div>

      <style>
        {`
          @keyframes slideDown {
            0% { opacity: 0; transform: translateY(-20px); }
            100% { opacity: 1; transform: translateY(0); }
          }
          .animate-slide-down {
            animation: slideDown 0.3s ease-out;
          }
